266→          });
267→        })
268→        .catch((error) => {
269→          log(`Error handling comment on issue #${issueNumber}: ${error}`, 'error');
270→          spawnDetached('npx', ['tsx', 'adws/adwPlanBuildTest.tsx', String(issueNumber), ...commentTargetRepoArgs]);
271→        });
272→
273→      jsonResponse(res, 200, { status: 'processing', issue: issueNumber });
274→      return;
