290→            log(`PR close event handled: ${JSON.stringify(result)}`);
291→          })
292→          .catch((error) => {
293→            log(`Error handling PR close event: ${error}`, 'error');
294→          });
295→        jsonResponse(res, 200, { status: 'processing' });
296→        return;
297→      }
298→      log(`Ignored pull_request action: ${action}`);
299→      jsonResponse(res, 200, { status: 'ignored' });
300→      return;
301→    }
302→
303→    // Handle issue events
304→    if (event !== 'issues') {
305→      log(`Ignored event: ${event || '(none)'}`);
306→      jsonResponse(res, 200, { status: 'ignored' });
307→      return;
308→    }
309→
310→    const action = (body.action as string) || '';
311→    const issue = (body.issue as Record<string, unknown> | undefined);
312→    const issueNumber = issue?.number as number | undefined;
313→
314→    if (issueNumber == null) {
315→      log('No issue number found in payload');
316→      jsonResponse(res, 200, { status: 'ignored' });
317→      return;
318→    }
319→
320→    if (action === 'closed') {
321→      log(`Issue #${issueNumber} closed, removing associated worktrees`);
322→      const closedRepository = body.repository as Record<string, unknown> | undefined;
323→      const closedRepoFullName = closedRepository?.full_name as string | undefined;
324→      if (closedRepoFullName) {
325→        setTargetRepo(getRepoInfoFromPayload(closedRepoFullName));
326→      }
327→      const closedTargetRepoArgs = extractTargetRepoArgs(body);
328→      const closedTargetRepoFullName = closedTargetRepoArgs.length >= 2 ? closedTargetRepoArgs[1] : undefined;
329→      const closedRepoParts = closedTargetRepoFullName?.split('/');
330→      const closedRepoCwd = closedRepoParts && closedRepoParts.length === 2
331→        ? getTargetRepoWorkspacePath(closedRepoParts[0], closedRepoParts[1])
332→        : undefined;
333→      const removed = removeWorktreesForIssue(issueNumber, closedRepoCwd);
334→      log(`Removed ${removed} worktree(s) for issue #${issueNumber}`, 'success');
335→      jsonResponse(res, 200, { status: 'worktrees_cleaned', issue: issueNumber, removed });
336→      return;
337→    }
338→
339→    if (action === 'opened') {
340→      log(`New issue #${issueNumber} detected, classifying and triggering ADW workflow`);
341→
342→      // Classify the issue and spawn the appropriate workflow asynchronously
343→      // Respond quickly to avoid GitHub timeout
344→      const issueTargetRepoArgs = extractTargetRepoArgs(body);
345→      const issueRepository = body.repository as Record<string, unknown> | undefined;
346→      const issueRepoFullName = issueRepository?.full_name as string | undefined;
347→      const issueRepoInfo = issueRepoFullName ? getRepoInfoFromPayload(issueRepoFullName) : undefined;
348→      if (issueRepoInfo) {
349→        setTargetRepo(issueRepoInfo);
350→      }
351→      classifyIssueForTrigger(issueNumber, issueRepoInfo)
352→        .then((classification) => {
353→          const workflowScript = getWorkflowScript(classification.issueType, classification.adwCommand);
354→          log(
355→            `Issue #${issueNumber} classified as ${classification.issueType}, spawning ${workflowScript}`,
356→            'success'
357→          );
358→          const adwIdArgs = classification.adwId ? [classification.adwId] : [];
359→          spawnDetached('npx', ['tsx', workflowScript, String(issueNumber), ...adwIdArgs, '--issue-type', classification.issueType, ...issueTargetRepoArgs]);
360→        })
361→        .catch((error) => {
362→          log(`Error classifying issue #${issueNumber}: ${error}, defaulting to adwPlanBuildTest.tsx`, 'error');
363→          spawnDetached('npx', ['tsx', 'adws/adwPlanBuildTest.tsx', String(issueNumber), ...issueTargetRepoArgs]);
364→        });
365→
366→      jsonResponse(res, 200, { status: 'processing', issue: issueNumber });
367→      return;
368→    }
369→
370→    log(`Ignored issues action: ${action}`);
371→    jsonResponse(res, 200, { status: 'ignored' });
372→  });
373→});
374→
375→/**
376→ * Resolves the port the webhook server should listen on.
377→ * Uses the preferred port if available, otherwise allocates a random available port.
378→ */
379→export async function resolveWebhookPort(preferredPort: number): Promise<number> {
380→  const available = await isPortAvailable(preferredPort, '0.0.0.0');
381→  if (available) {
382→    return preferredPort;
383→  }
384→  log(`Port ${preferredPort} is in use, allocating a random available port...`, 'warn');
385→  return allocateRandomPort();
386→}
387→
388→async function startServer(): Promise<void> {
389→  const preferredPort = parseInt(process.env.PORT || '8001', 10);
390→  const actualPort = await resolveWebhookPort(preferredPort);
391→  log(`Starting webhook trigger on port ${actualPort}`);
392→
393→  server.once('error', async (err: NodeJS.ErrnoException) => {
394→    if (err.code === 'EADDRINUSE') {
395→      log(`Port ${actualPort} was taken (TOCTOU race), retrying with a random port...`, 'warn');
396→      const retryPort = await allocateRandomPort();
397→      server.listen(retryPort, '0.0.0.0', () => {
398→        log(`Webhook server listening on 0.0.0.0:${retryPort}`);
399→      });
400→    } else {
401→      throw err;
402→    }
403→  });
404→
405→  server.listen(actualPort, '0.0.0.0', () => {
406→    log(`Webhook server listening on 0.0.0.0:${actualPort}`);
407→  });
408→}
409→
410→startServer().catch((error) => {
411→  log(`Fatal error starting webhook server: ${error}`, 'error');
412→});
