import { createHmac, timingSafeEqual } from 'node:crypto';

/**
 * Validates a GitHub webhook HMAC-SHA256 signature against the raw request body.
 * Uses constant-time comparison to prevent timing attacks.
 *
 * @param rawBody - The raw request body as a Buffer (must match what GitHub signed)
 * @param signatureHeader - The value of the `x-hub-signature-256` header (e.g. `sha256=abc123...`)
 * @param secret - The webhook secret configured in GitHub and locally
 * @returns `true` if the signature is valid, `false` otherwise
 */
export function verifyWebhookSignature(
  rawBody: Buffer,
  signatureHeader: string | undefined,
  secret: string,
): boolean {
  if (!signatureHeader) {
    return false;
  }

  const expectedSignature = `sha256=${createHmac('sha256', secret).update(rawBody).digest('hex')}`;

  // Length check before timingSafeEqual (which requires equal-length buffers)
  const sigBuffer = Buffer.from(signatureHeader);
  const expectedBuffer = Buffer.from(expectedSignature);

  if (sigBuffer.length !== expectedBuffer.length) {
    return false;
  }

  return timingSafeEqual(sigBuffer, expectedBuffer);
}

