export async function resolveWebhookPort(preferredPort: number): Promise<number> {
  const available = await isPortAvailable(preferredPort, '0.0.0.0');
  if (available) {
    return preferredPort;
  }

  // In tunnel mode (secret configured), a random port would silently break the tunnel
  if (process.env.GITHUB_WEBHOOK_SECRET) {
    throw new Error(
      `Port ${preferredPort} is in use and GITHUB_WEBHOOK_SECRET is set (tunnel mode). ` +
      `The Cloudflare tunnel expects port ${preferredPort}. Free the port or update the tunnel config.`
    );
  }

  log(`Port ${preferredPort} is in use, allocating a random available port...`, 'warn');
  return allocateRandomPort();
}

