import { describe, it, expect } from 'vitest';
import { createHmac } from 'node:crypto';
import { verifyWebhookSignature } from '../triggers/webhookSignature';

const SECRET = 'test-webhook-secret-key';

function sign(body: Buffer, secret: string): string {
  return `sha256=${createHmac('sha256', secret).update(body).digest('hex')}`;
}

describe('verifyWebhookSignature', () => {
  const payload = Buffer.from(JSON.stringify({ action: 'opened', issue: { number: 1 } }));

  it('accepts a valid signature', () => {
    const signature = sign(payload, SECRET);
    expect(verifyWebhookSignature(payload, signature, SECRET)).toBe(true);
  });

  it('rejects when signature header is missing', () => {
    expect(verifyWebhookSignature(payload, undefined, SECRET)).toBe(false);
  });

  it('rejects when signature header is empty string', () => {
    expect(verifyWebhookSignature(payload, '', SECRET)).toBe(false);
  });

  it('rejects when signed with a different secret', () => {
    const wrongSignature = sign(payload, 'wrong-secret');
    expect(verifyWebhookSignature(payload, wrongSignature, SECRET)).toBe(false);
  });

  it('rejects when payload has been tampered with', () => {
    const signature = sign(payload, SECRET);
    const tampered = Buffer.from(JSON.stringify({ action: 'opened', issue: { number: 999 } }));
    expect(verifyWebhookSignature(tampered, signature, SECRET)).toBe(false);
  });

  it('rejects a signature with wrong length', () => {
    expect(verifyWebhookSignature(payload, 'sha256=tooshort', SECRET)).toBe(false);
  });

  it('rejects a completely malformed signature', () => {
    expect(verifyWebhookSignature(payload, 'not-a-valid-signature', SECRET)).toBe(false);
  });
});

